import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class CommentWrappingRuleReproductionTest {
    private val commentWrappingRuleAssertThat = assertThatRule { CommentWrappingRule() }

    @Test
    fun `Given a single line block containing a block comment then do not wrap this comment to a multiline block`() {
        val code =
